BEGIN TRANSACTION;
CREATE TABLE attack_details (
        traffic_log_id INTEGER PRIMARY KEY,
        raw_payload TEXT,
        response_payload TEXT,
        attack_vector TEXT,
        risk_level INTEGER,
        hits INTEGER,
        interaction_depth INTEGER,
        dwell_time REAL,
        mitigation_status TEXT,
        FOREIGN KEY(traffic_log_id) REFERENCES traffic_logs(id)
    );
CREATE TABLE clients (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        ip TEXT UNIQUE NOT NULL,
        polluted_status INTEGER DEFAULT 0
    );
CREATE TABLE fingerprints (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        user_agent TEXT,
        tls_fingerprint TEXT,
        UNIQUE(user_agent, tls_fingerprint)
    );
CREATE TABLE traffic_logs (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        request_at TEXT NOT NULL,
        response_at TEXT,
        process_ms INTEGER,
        client_id INTEGER NOT NULL,
        fingerprint_id INTEGER,
        query_id TEXT,
        is_attack INTEGER DEFAULT 0,
        location TEXT,
        is_proxy INTEGER DEFAULT 0,
        FOREIGN KEY(client_id) REFERENCES clients(id),
        FOREIGN KEY(fingerprint_id) REFERENCES fingerprints(id)
    );
CREATE INDEX idx_traffic_logs_is_attack ON traffic_logs(is_attack);
CREATE INDEX idx_traffic_logs_request_at ON traffic_logs(request_at);
CREATE INDEX idx_clients_ip ON clients(ip);
DELETE FROM "sqlite_sequence";
COMMIT;